import React, { useState, useEffect } from 'react';
import {
  Box,
  Container,
  Typography,
  Grid,
  Paper,
  Card,
  CardContent,
  Table,
  TableBody,
  TableCell,
  TableContainer,
  TableHead,
  TableRow,
  Button,
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
  TextField,
  IconButton,
  Alert,
  Chip,
  Tabs,
  Tab,
  Avatar,
  Tooltip,
} from '@mui/material';
import {
  People as PeopleIcon,
  Event as EventIcon,
  AccessTime as TimeIcon,
  Close as CloseIcon,
  CheckCircle as CheckCircleIcon,
  Cancel as CancelIcon,
  CalendarToday,
  AccessTime,
  Person,
  LocalHospital,
  Edit,
  Assignment,
  Search,
} from '@mui/icons-material';
import { useAuth } from '../../context/AuthContext';
import axios from 'axios';
import { format } from 'date-fns';

const Dashboard = () => {
  const { user } = useAuth();
  const [stats, setStats] = useState({
    totalPatients: 0,
    todayAppointments: 0,
    pendingAppointments: 0,
    completedAppointments: 0,
  });
  const [appointments, setAppointments] = useState([]);
  const [selectedAppointment, setSelectedAppointment] = useState(null);
  const [openPrescriptionDialog, setOpenPrescriptionDialog] = useState(false);
  const [prescriptionNote, setPrescriptionNote] = useState('');
  const [activeTab, setActiveTab] = useState(0);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchDashboardData();
  }, [user]);

  const fetchDashboardData = async () => {
    try {
      const [appointmentsRes, statsRes] = await Promise.all([
        axios.get(`http://localhost:5000/api/appointments/doctor/${user.id}`),
        axios.get(`http://localhost:5000/api/doctors/${user.id}/stats`),
      ]);
      setAppointments(appointmentsRes.data);
      setStats(statsRes.data);
      setLoading(false);
    } catch (error) {
      console.error('Error fetching dashboard data:', error);
      setError('Failed to fetch dashboard data');
      setLoading(false);
    }
  };

  const handleTabChange = (event, newValue) => {
    setActiveTab(newValue);
  };

  const handleOpenPrescription = (appointment) => {
    setSelectedAppointment(appointment);
    setPrescriptionNote('');
    setOpenPrescriptionDialog(true);
  };

  const handleClosePrescription = () => {
    setOpenPrescriptionDialog(false);
    setSelectedAppointment(null);
    setPrescriptionNote('');
  };

  const handleSubmitPrescription = async () => {
    try {
      await axios.post(`http://localhost:5000/api/prescriptions`, {
        appointmentId: selectedAppointment.id,
        doctorId: user.id,
        patientId: selectedAppointment.patientId,
        notes: prescriptionNote,
      });
      await handleUpdateAppointment(selectedAppointment.id, 'completed');
      handleClosePrescription();
      fetchDashboardData();
    } catch (error) {
      console.error('Error submitting prescription:', error);
    }
  };

  const handleUpdateAppointment = async (appointmentId, status) => {
    try {
      await axios.put(`http://localhost:5000/api/appointments/${appointmentId}/status`, {
        status,
      });
      fetchDashboardData();
    } catch (error) {
      console.error('Error updating appointment:', error);
    }
  };

  const getStatusColor = (status) => {
    switch (status) {
      case 'pending':
        return 'warning';
      case 'completed':
        return 'success';
      case 'cancelled':
        return 'error';
      default:
        return 'default';
    }
  };

  const filterAppointments = () => {
    const today = new Date().toISOString().split('T')[0];
    switch (activeTab) {
      case 0: // Today's appointments
        return appointments.filter(apt => apt.date.startsWith(today));
      case 1: // Upcoming appointments
        return appointments.filter(apt => 
          apt.status === 'pending' && apt.date >= today
        );
      case 2: // Past appointments
        return appointments.filter(apt => 
          apt.status === 'completed' || apt.date < today
        );
      default:
        return appointments;
    }
  };

  const StatCard = ({ icon: Icon, title, value, color }) => (
    <Card>
      <CardContent>
        <Box display="flex" alignItems="center" mb={2}>
          <Icon sx={{ fontSize: 40, color }} />
          <Typography variant="h6" ml={2} color="text.secondary">
            {title}
          </Typography>
        </Box>
        <Typography variant="h4" component="div">
          {value}
        </Typography>
      </CardContent>
    </Card>
  );

  if (loading) {
    return (
      <Container maxWidth="lg">
        <Typography>Loading...</Typography>
      </Container>
    );
  }

  return (
    <Container maxWidth="lg" sx={{ mt: 4, mb: 4 }}>
      <Typography variant="h4" component="h1" gutterBottom>
        Doctor Dashboard
      </Typography>

      {error && <Alert severity="error" sx={{ mb: 2 }}>{error}</Alert>}
      {success && <Alert severity="success" sx={{ mb: 2 }}>{success}</Alert>}

      <Grid container spacing={3} mb={4}>
        <Grid item xs={12} sm={6} md={3}>
          <StatCard
            icon={PeopleIcon}
            title="Total Patients"
            value={stats.totalPatients}
            color="#1976d2"
          />
        </Grid>
        <Grid item xs={12} sm={6} md={3}>
          <StatCard
            icon={EventIcon}
            title="Today's Appointments"
            value={stats.todayAppointments}
            color="#2e7d32"
          />
        </Grid>
        <Grid item xs={12} sm={6} md={3}>
          <StatCard
            icon={TimeIcon}
            title="Pending"
            value={stats.pendingAppointments}
            color="#ed6c02"
          />
        </Grid>
        <Grid item xs={12} sm={6} md={3}>
          <StatCard
            icon={CheckCircleIcon}
            title="Completed"
            value={stats.completedAppointments}
            color="#1976d2"
          />
        </Grid>
      </Grid>

      <Paper sx={{ p: 3 }}>
        <Box sx={{ borderBottom: 1, borderColor: 'divider', mb: 2 }}>
          <Tabs value={activeTab} onChange={handleTabChange}>
            <Tab label="Today's Appointments" />
            <Tab label="Upcoming Appointments" />
            <Tab label="Past Appointments" />
          </Tabs>
        </Box>

        <TableContainer>
          <Table>
            <TableHead>
              <TableRow>
                <TableCell>Patient</TableCell>
                <TableCell>Date & Time</TableCell>
                <TableCell>Type</TableCell>
                <TableCell>Symptoms</TableCell>
                <TableCell>Status</TableCell>
                <TableCell>Actions</TableCell>
              </TableRow>
            </TableHead>
            <TableBody>
              {filterAppointments().map((appointment) => (
                <TableRow key={appointment.id}>
                  <TableCell>
                    <Box sx={{ display: 'flex', alignItems: 'center' }}>
                      <Avatar sx={{ mr: 2 }}>{appointment.patientName[0]}</Avatar>
                      <Box>
                        <Typography variant="subtitle2">
                          {appointment.patientName}
                        </Typography>
                        <Typography variant="body2" color="textSecondary">
                          ID: {appointment.patientId}
                        </Typography>
                      </Box>
                    </Box>
                  </TableCell>
                  <TableCell>
                    <Typography variant="subtitle2">
                      {new Date(appointment.date).toLocaleDateString()}
                    </Typography>
                    <Typography variant="body2" color="textSecondary">
                      {appointment.time}
                    </Typography>
                  </TableCell>
                  <TableCell>{appointment.type}</TableCell>
                  <TableCell>{appointment.symptoms}</TableCell>
                  <TableCell>
                    <Chip
                      label={appointment.status}
                      color={getStatusColor(appointment.status)}
                      size="small"
                    />
                  </TableCell>
                  <TableCell>
                    {appointment.status === 'pending' && (
                      <Box>
                        <Tooltip title="Complete & Add Prescription">
                          <IconButton
                            color="primary"
                            onClick={() => handleOpenPrescription(appointment)}
                          >
                            <Assignment />
                          </IconButton>
                        </Tooltip>
                        <Tooltip title="Cancel Appointment">
                          <IconButton
                            color="error"
                            onClick={() => handleUpdateAppointment(appointment.id, 'cancelled')}
                          >
                            <CancelIcon />
                          </IconButton>
                        </Tooltip>
                      </Box>
                    )}
                  </TableCell>
                </TableRow>
              ))}
              {filterAppointments().length === 0 && (
                <TableRow>
                  <TableCell colSpan={5} align="center">
                    No appointments found
                  </TableCell>
                </TableRow>
              )}
            </TableBody>
          </Table>
        </TableContainer>
      </Paper>

      {/* Prescription Dialog */}
      <Dialog
        open={openPrescriptionDialog}
        onClose={handleClosePrescription}
        maxWidth="md"
        fullWidth
      >
        <DialogTitle>Add Prescription</DialogTitle>
        <DialogContent>
          <Box sx={{ mt: 2 }}>
            <TextField
              label="Prescription Notes"
              multiline
              rows={6}
              fullWidth
              value={prescriptionNote}
              onChange={(e) => setPrescriptionNote(e.target.value)}
              placeholder="Enter prescription details, medications, and instructions..."
            />
          </Box>
        </DialogContent>
        <DialogActions>
          <Button onClick={handleClosePrescription}>Cancel</Button>
          <Button
            onClick={handleSubmitPrescription}
            variant="contained"
            color="primary"
            disabled={!prescriptionNote.trim()}
          >
            Submit & Complete Appointment
          </Button>
        </DialogActions>
      </Dialog>
    </Container>
  );
};

export default Dashboard;
